        self.tokens = tokens
        self.pos = 0

    def peek(self):
        return self.tokens[self.pos] if self.pos < len(self.tokens) else None

    def consume(self):
        t = self.tokens[self.pos]
        self.pos += 1
        return t

    def parse(self):
        node = self.expression()
        if self.peek() is not None:
            raise ValueError("Extra tokens after expression")
        return node

    def expression(self):
        node = self.term()
        while self.peek() in ('+', '-'):
            op = self.consume()
            node = ASTNode('binop', op=op, left=node, right=self.term())
        return node

    def term(self):
        node = self.unary()
        while self.peek() in ('*', '/'):
            op = self.consume()
            node = ASTNode('binop', op=op, left=node, right=self.unary())
        return node

    def unary(self):
        if self.peek() == '-':
            self.consume()
            return ASTNode('unary', op='-', operand=self.unary())
        return self.primary()

    def primary(self):
        t = self.peek()
        if t == '(':
            self.consume()
            node = self.expression()
            if self.peek() != ')':
                raise ValueError("Unmatched parenthesis")
